+                .name = col_names[1 + a],
+                .data = .{ .float64 = agg_data },
+            };
+        }
+
+        return Result{
+            .columns = columns,
+            .row_count = num_groups,
+            .allocator = self.allocator,
+            .owns_data = true,
+        };
+    }
